import anthropic, json

PERSONA_PROFILES = {
    "legal_analyst": {
        "failure_tolerance": "Zero Tolerance",
        "domain_expertise": "Subject-Matter Expert",
        "trust_posture": "Sceptic",
    },
    "marketing_manager": {
        "failure_tolerance": "Tolerates Frequent Misses",
        "domain_expertise": "Informed",
        "trust_posture": "Enthusiast",
    },
    "software_engineer": {
        "failure_tolerance": "Accepts Occasional Errors",
        "domain_expertise": "Practitioner",
        "trust_posture": "Pragmatist",
    },
}

def derive_eval_thresholds(persona_id: str, task_category: str) -> dict:
    """
    Derive quantitative eval pass/fail thresholds from persona dimension scores.
    These thresholds configure the CI eval gate for the feature.
    """
    client = anthropic.Anthropic()
    persona = PERSONA_PROFILES[persona_id]

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        tools=[{
            "name": "eval_thresholds",
            "description": "Output quantitative eval thresholds derived from persona",
            "input_schema": {
                "type": "object",
                "properties": {
                    "factual_accuracy_min_pct": {"type": "number", "description": "Minimum factual accuracy score (0-100)"},
                    "format_compliance_min_pct": {"type": "number"},
                    "citation_required": {"type": "boolean"},
                    "uncertainty_marking_required": {"type": "boolean"},
                    "max_hallucination_rate_pct": {"type": "number"},
                    "rationale": {"type": "string"},
                },
                "required": ["factual_accuracy_min_pct","format_compliance_min_pct",
                             "citation_required","uncertainty_marking_required",
                             "max_hallucination_rate_pct","rationale"]
            }
        }],
        tool_choice={"type": "tool", "name": "eval_thresholds"},
        messages=[{"role": "user", "content": f"""
Persona: {persona_id}
  - Failure tolerance: {persona['failure_tolerance']}
  - Domain expertise: {persona['domain_expertise']}
  - Trust posture: {persona['trust_posture']}

Task category: {task_category}

Derive appropriate eval pass/fail thresholds for this persona × task combination.
Higher failure tolerance → lower minimum scores.
Higher domain expertise → citation required = True.
Trust posture Sceptic → uncertainty marking required = True."""}]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    return {}

# Compare thresholds across personas for the same task
for persona_id in PERSONA_PROFILES:
    thresholds = derive_eval_thresholds(persona_id, task_category="contract clause review")
    print(f"\n=== {persona_id} ===")
    print(f"  Factual accuracy min: {thresholds.get('factual_accuracy_min_pct')}%")
    print(f"  Max hallucination rate: {thresholds.get('max_hallucination_rate_pct')}%")
    print(f"  Citations required: {thresholds.get('citation_required')}")
    print(f"  Uncertainty marking: {thresholds.get('uncertainty_marking_required')}")
